// runner-store · useDayRunner(v1 React hook) 翻译为 Pinia setup store。
// 用 setup 语法(对齐模板 settings.ts): ref ≈ useState, 函数 ≈ useCallback。
// 业务逻辑全部复用 src/jiutiao/game/* 纯 TS 模块(零改动)。
//
// 注: defineStore / ref / computed 都是 webpack auto-import 注入的全局,不手动 import。
//   当前用本地 initialEngine(mock 起步)。阶段2末尾改为从 MVU stat_data 初始化 + 双向回写。
import { startDay, allocate as allocateFn, setChoice as setChoiceFn, clearChoice as clearChoiceFn, beginDay as beginDayFn, beginNight as beginNightFn, fillEmpty as fillEmptyFn, currentSlot, } from '../../game/action-grid/machine';
import { runCurrentSlot, settleNight, advanceToNextDay, applyForcedSeizes } from '../../game/engine/day-runner';
import { demoEventOptions, demoSummaryTemplates, demoExtractBounds, demoForcedPool, createMockAi, } from '../../game/engine/mock-ai';
import { demoLorebook } from '../../game/worldbook/demo';
import { createTavernAi } from './tavern-ai';
const DEFAULT_FORCED_LEAVE_CHOICE = { optionId: 'serve_vaginal', label: '供奉（强制请假轮奸）' };
const TOTAL_SLOTS = 8;
function initialEngine() {
    return {
        triggeredSpecials: {}, unlocked: {},
        corruption: 0, cognition: '死撑', claimedGates: {},
        money: 8000, thugTotal: 30, garrison: 0, loyalty: 60,
        condomStock: 480, desire: 0, desireCapacity: 60, perSlotThroughput: 6,
        infamy: 0, martialPrestige: 0,
        recruitQuota: 0, presentCount: 18, isDangerousPeriod: false,
        servedThisNight: 0,
    };
}
export const useRunnerStore = defineStore('runner', () => {
    // ─── state(ref ≈ useState) ───
    const day = ref(startDay(1, TOTAL_SLOTS));
    const engine = ref(initialEngine());
    const fastForward = ref(false);
    const busy = ref(false);
    const lastSettle = ref(null);
    const lastServe = ref(null);
    const lastNight = ref(null);
    const forcedLeaveToday = ref(false);
    const forcedSeize = ref(null);
    const reliefCleared = ref(false);
    const hardFail = ref(false);
    const error = ref(null);
    // AI 端口: 默认接酒馆 generate(套预设/JB,出真实正文);
    // 检测不到酒馆 generate 全局(本地开发/异常)时回落 mock。
    // useMock() 可手动切回 mock 调试。
    const hasTavernGenerate = typeof globalThis.generate === 'function';
    let ai = hasTavernGenerate
        ? createTavernAi({ lorebook: demoLorebook })
        : createMockAi();
    const aiMode = ref(hasTavernGenerate ? 'tavern' : 'mock');
    function useMock() { ai = createMockAi(); aiMode.value = 'mock'; }
    function useTavern() { ai = createTavernAi({ lorebook: demoLorebook }); aiMode.value = 'tavern'; }
    // ─── getters(computed) ───
    const currentSlotRef = computed(() => currentSlot(day.value));
    const canRunCurrent = computed(() => {
        const cur = currentSlotRef.value;
        return !!cur && !!cur.choice;
    });
    const runnerState = computed(() => ({ day: day.value, engine: engine.value }));
    function settleOptions() {
        return {
            eventOptions: demoEventOptions,
            ai,
            summaryTemplates: demoSummaryTemplates,
            extractBounds: demoExtractBounds,
            forcedPool: demoForcedPool,
            fastForward: fastForward.value,
            rng: Math.random,
        };
    }
    // ─── actions(函数 ≈ useCallback) ───
    function setFastForward(v) { fastForward.value = v; }
    function allocate(dayCount, nightCount) {
        const r = allocateFn(day.value, { dayCount, nightCount });
        if (!r.ok) {
            error.value = r.error;
            return false;
        }
        const seized = applyForcedSeizes(r.state, engine.value, demoForcedPool);
        error.value = null;
        day.value = seized.day;
        forcedSeize.value = seized.fired;
        return true;
    }
    function setChoice(period, index, choice) {
        try {
            day.value = setChoiceFn(day.value, period, index, choice);
            error.value = null;
        }
        catch (e) {
            error.value = e.message;
        }
    }
    function clearChoice(period, index) {
        try {
            day.value = clearChoiceFn(day.value, period, index);
            error.value = null;
        }
        catch (e) {
            error.value = e.message;
        }
    }
    function beginDay() {
        try {
            day.value = beginDayFn(day.value);
            error.value = null;
            return true;
        }
        catch (e) {
            error.value = e.message;
            return false;
        }
    }
    function beginNight() {
        try {
            day.value = beginNightFn(day.value);
            error.value = null;
            return true;
        }
        catch (e) {
            error.value = e.message;
            return false;
        }
    }
    function fillEmpty(period, choice) {
        day.value = fillEmptyFn(day.value, period, choice);
        error.value = null;
    }
    async function runCurrent() {
        if (busy.value)
            return;
        busy.value = true;
        error.value = null;
        try {
            const state = { day: day.value, engine: engine.value };
            const r = await runCurrentSlot(state, settleOptions());
            let nextEngine = r.state.engine;
            let nightInfo = null;
            if (r.state.day.phase === 'night_settled') {
                const ns = settleNight(nextEngine);
                nextEngine = ns.state;
                nightInfo = ns;
            }
            day.value = r.state.day;
            engine.value = nextEngine;
            lastSettle.value = r.settle;
            lastServe.value = r.serve ?? null;
            lastNight.value = nightInfo;
        }
        catch (e) {
            error.value = e.message;
        }
        finally {
            busy.value = false;
        }
    }
    function nextDay() {
        const r = advanceToNextDay(engine.value, day.value.dayNumber, engine.value.totalSlots ?? TOTAL_SLOTS, DEFAULT_FORCED_LEAVE_CHOICE, day.value.dayCount === 0);
        engine.value = r.engine;
        day.value = r.day;
        forcedLeaveToday.value = r.forcedLeave;
        reliefCleared.value = r.reliefCleared;
        hardFail.value = r.daily.hardFail;
        forcedSeize.value = null;
        lastSettle.value = null;
        lastServe.value = null;
        lastNight.value = null;
        error.value = null;
    }
    function loadState(state, ff) {
        day.value = state.day;
        engine.value = state.engine;
        fastForward.value = ff;
        lastSettle.value = null;
        lastServe.value = null;
        lastNight.value = null;
        forcedLeaveToday.value = false;
        forcedSeize.value = null;
        reliefCleared.value = false;
        hardFail.value = false;
        error.value = null;
    }
    return {
        day, engine, fastForward, busy, lastSettle, lastServe, lastNight,
        forcedLeaveToday, forcedSeize, reliefCleared, hardFail, error,
        currentSlot: currentSlotRef, canRunCurrent, runnerState,
        aiMode,
        setFastForward, allocate, setChoice, clearChoice, fillEmpty,
        beginDay, beginNight, runCurrent, nextDay, loadState,
        useMock, useTavern,
    };
});
